import { useState, useEffect, useRef } from "react";
import 'bootstrap-icons/font/bootstrap-icons.css';

function EditorQuill({ placeholder, onReady }) {
  const contenedor = useRef(null);
  const iniciado = useRef(false);

  useEffect(() => {
    if (iniciado.current) return;
    iniciado.current = true;

    const Parchment = window.Quill.import("parchment");
    const AlignStyle = new Parchment.Attributor.Style(
      "align", "text-align",
      { scope: Parchment.Scope.BLOCK, whitelist: ["left", "center", "justify"] }
    );
    window.Quill.register(AlignStyle, true);

    const quill = new window.Quill(contenedor.current, {
      theme: "snow",
      placeholder: placeholder || "Escribe aquí...",
      modules: {
        toolbar: [
          ["bold", "italic", "underline"],
          [{ align: '' }, { align: 'center' }, { align: 'justify' }],
          [{ list: "ordered" }, { list: "bullet" }],
          ["link"],
          ["clean"],
        ],
      },
    });

    onReady(quill);
  }, []);

  return (
    <div style={{ position: "relative" }}>
      <div ref={contenedor} style={{ background: "#fff", height: 150, overflowY: "auto" }} />
    </div>
  );
}

  const logoCabezera = "data:image/png;base64,";
  const logoPie = "data:image/png;base64,";
  const whatsAppImage = "data:image/png;base64,";
  const xImage = "data:image/png;base64,";
  const facebookImage = "data:image/png;base64,";
  const instagramImage = "data:image/png;base64,";


const piePagina = `
  <tr>
    <td style="padding:18px 24px; border-top:1px solid #E5E7EB; text-align:center;">
      <p style="direction:ltr; margin:10px 0px 6px">
        <a target="_blank" href="https://www.fvmp.es/?lang=ca" style="text-decoration:none; margin-top:0px; margin-bottom:0px">
          <img height="122" width="101"
            src="${logoPie}" alt="logo"
            style="width:101.483px; height:122px; max-width:1171px; margin-top:0px; margin-bottom:0px">
        </a><br>
        <span style="font-family:Arial,sans-serif; font-size:14px; color:rgb(0,0,0)">
          <a target="_blank" href="https://www.fvmp.es/bando-fvmp/?lang=ca" style="text-decoration:none; margin-top:0px; margin-bottom:0px">
            <img height="43" width="43" src="${whatsAppImage}" style="width:43px; height:43px; max-width:1166px; margin-top:0px; margin-bottom:0px">
          </a>
          <a target="_blank" href="https://x.com/fvmpendirecto?lang=es" style="text-decoration:none; margin-top:0px; margin-bottom:0px">
            <img src="${xImage}" style="max-width:1166px; margin-top:0px; margin-bottom:0px">
          </a>
          <a target="_blank" href="https://www.facebook.com/FederacionValencianadeMunicipiosyProvincias/about?locale=es_ES" style="text-decoration:none; margin-top:0px; margin-bottom:0px">
            <img src="${facebookImage}" style="max-width:1166px; margin-top:0px; margin-bottom:0px">
          </a>
          <a target="_blank" href="https://www.instagram.com/fvmpcomunicacion/?hl=es" style="text-decoration:none; margin-top:0px; margin-bottom:0px">
            <img src="${instagramImage}" style="max-width:1166px; margin-top:0px; margin-bottom:0px">
          </a>
        </span>
      </p>
      <p style="margin:0 0 6px 0; font-family:Arial, sans-serif; font-size:14px; color:#53565A;">
        <strong>Secretaría General</strong>
      </p>
      <p style="margin:0; font-family:Arial, sans-serif; font-size:13px; color:#53565A; line-height:19px;">
        962935112 / 963913902 – ext. 2207<br>
        <a target="_blank" href="mailto:secretariageneral@fvmp.org" style="color:#005FB8; text-decoration:underline;">secretariageneral@fvmp.org</a><br>
        <a target="_blank" href="https://www.fvmp.es" style="color:#005FB8; text-decoration:underline;">https://www.fvmp.es</a><br>
        C\\ Guillem de Castro 46, 1ª planta. 46001 Valencia
      </p>
    </td>
  </tr>
  <tr>
    <td style="padding:14px 24px 24px 24px; font-family:Arial, sans-serif;">
      <p style="margin:0 0 6px 0; font-size:12px; color:#53565A;"><strong>Aviso legal / Avís legal</strong></p>
      <p style="margin:0; font-size:11px; line-height:16px; color:#6A6D70; text-align: justify;">
        <strong>ES:</strong> Este mensaje electrónico está dirigido únicamente al destinatario designado. Su carácter personal e intransferible está protegido legalmente. Cualquier revelación, uso o reenvío no autorizado está prohibida. Si ha recibido este mensaje por error, rogamos lo notifique de inmediato a la persona que lo remite y borre el mensaje original junto con sus ficheros anexos sin leerlo ni grabarlo, total o parcialmente.
        <br><br>
        En cumplimiento de las Leyes 34/2002 y 3/2018 le comunicamos que su dirección de correo electrónico forma parte de un fichero con la finalidad de cumplimiento de las funciones de la FVMP. Si lo desea puede ejercer sus derechos enviando un correo a
        <a target="_blank" href="mailto:protecciondedatos@fvmp.org" style="color:#005FB8; text-decoration:underline;">protecciondedatos@fvmp.org</a>.
        <br><br>
        <strong>VA:</strong> Aquest missatge electrònic està dirigit únicament al destinatari designat. El seu caràcter personal i intransferible està protegit legalment. Qualsevol revelació, ús o reexpedició no autoritzat està prohibit. Si ha rebut aquest missatge per error, preguem que ho notifique immediatament a la persona que ho remet i esborre el missatge original juntament amb els seus fitxers annexos sense llegir-lo ni gravar-lo, totalment o parcialment.
        <br><br>
        En compliment de les Lleis 34/2002 i 3/2018, li comuniquem que la seua adreça de correu electrònic forma part d'un fitxer amb la finalitat de donar compliment de les funcions de la FVMP. Si ho desitja pot exercir els seus drets enviant un correu a
        <a target="_blank" href="mailto:protecciondedatos@fvmp.org" style="color:#005FB8; text-decoration:underline;">protecciondedatos@fvmp.org</a>.
      </p>
    </td>
  </tr>`;

export default function App() {
  const [titulo, setTitulo] = useState("");
  const [tituloVa, setTituloVa] = useState("");
  const [imagenCabecera, setImagenCabecera] = useState("");
  const [imagenCabeceraVa, setImagenCabeceraVa] = useState("");

  const [bloques, setBloques] = useState([]);

  const [hojaVaActiva, setHojaVaActiva] = useState(false);

  const [quillCargado, setQuillCargado] = useState(false);
  const [html, setHtml] = useState("");
  const [copiado, setCopiado] = useState(false);
  const [pestanaActiva, setPestanaActiva] = useState("es");

  const editoresQuill = useRef({});

  useEffect(() => {
    const link = document.createElement("link");
    link.rel = "stylesheet";
    link.href = "https://cdn.quilljs.com/1.3.7/quill.snow.css";
    document.head.appendChild(link);

    const script = document.createElement("script");
    script.src = "https://cdn.quilljs.com/1.3.7/quill.min.js";
    script.onload = () => setQuillCargado(true);
    document.head.appendChild(script);
  }, []);

  useEffect(() => {
    setHtml(generarHTML());
  }, [bloques, titulo, tituloVa, imagenCabecera, imagenCabeceraVa, hojaVaActiva]);

  function imagenCabeceraABase64(archivo, esVa = false) {
    const reader = new FileReader();
    reader.onload = e => {
      if (esVa) setImagenCabeceraVa(e.target.result);
      else setImagenCabecera(e.target.result);
    };
    reader.readAsDataURL(archivo);
  }

  function agregarBloque(tipo) {
    setBloques(prev => [...prev, {
      id: Date.now(),
      tipo,
      contenido: "",
      imagen: "",
      urlBoton: "",
      textoBoton: "Más información",
      colorBoton: "#005FB8",
      contenidoCol2: "",
      contenidoVa: "",
      imagenVa: "",
      urlBotonVa: "",
      textoBotonVa: "Més informació",
      colorBotonVa: "#005FB8",
      contenidoCol2Va: "",
    }]);
  }

  function actualizarBloque(id, campo, valor) {
    setBloques(prev => prev.map(b => b.id === id ? { ...b, [campo]: valor } : b));
  }

  function eliminarBloque(id) {
    ["contenido","contenidoVa","contenidoCol2","contenidoCol2Va"].forEach(c => {
      delete editoresQuill.current[id + "-" + c];
    });
    setBloques(prev => prev.filter(b => b.id !== id));
  }

  function imagenBloqueABase64(id, archivo, campoImagen) {
    const reader = new FileReader();
    reader.onload = e => actualizarBloque(id, campoImagen, e.target.result);
    reader.readAsDataURL(archivo);
  }

  function guardarEditor(id, campo, quill) {
    const key = id + "-" + campo;
    editoresQuill.current[key] = quill;
    quill.on("text-change", () => {
      actualizarBloque(id, campo, quill.root.innerHTML);
    });
  }

  function copiarHTML() {
    navigator.clipboard.writeText(html).then(() => {
      setCopiado(true);
      setTimeout(() => setCopiado(false), 2000);
    });
  }

  function renderBloquesHTML(sufijo) {
    let contenidoBloques = "";
    bloques.forEach(b => {
      const contenido = b["contenido" + sufijo] || "";
      const imagen = b["imagen" + sufijo] || "";
      const urlBoton = b["urlBoton" + sufijo] || "";
      const textoBoton = b["textoBoton" + sufijo] || "";
      const colorBoton = b["colorBoton" + sufijo] || "#005FB8";
      const contenidoCol2 = b["contenidoCol2" + sufijo] || "";

      if (b.tipo === "texto") {
        contenidoBloques += `
        <tr>
          <td style="padding:12px 24px; font-family:Arial,sans-serif; font-size:14px; color:#53565A; line-height:20px; word-break:break-word; overflow-wrap:break-word;">
            ${contenido}
          </td>
        </tr>`;
      } else if (b.tipo === "imagen") {
        contenidoBloques += `
        <tr>
          <td style="padding:12px 24px; text-align:center;">
            <img src="${imagen}" alt="imagen" style="width:100%; max-width:600px; height:auto; display:block; margin:0 auto;" />
          </td>
        </tr>`;
      } else if (b.tipo === "doscolumnas") {
        contenidoBloques += `
        <tr>
          <td style="padding:12px 24px;">
            <table width="100%" cellspacing="0" cellpadding="0" border="0">
              <tr>
                <td width="50%" valign="top" style="border:1px solid #E5E7EB; padding:12px; font-family:Arial,sans-serif; font-size:13px; color:#53565A; word-break:break-word; overflow-wrap:break-word;">
                  ${contenido}
                </td>
                <td width="50%" valign="top" style="border:1px solid #E5E7EB; padding:12px; font-family:Arial,sans-serif; font-size:13px; color:#53565A; word-break:break-word; overflow-wrap:break-word;">
                  ${contenidoCol2}
                </td>
              </tr>
            </table>
          </td>
        </tr>`;
      } else if (b.tipo === "caja") {
        contenidoBloques += `
        <tr>
          <td style="padding:12px 24px;">
            <table width="100%" cellspacing="0" cellpadding="0" border="0" style="border-left:4px solid #005FB8; background:#EEF5FD;">
              <tr>
                <td style="padding:12px; font-family:Arial,sans-serif; font-size:13px; color:#53565A; line-height:19px; word-break:break-word; overflow-wrap:break-word;">
                  ${contenido}
                </td>
              </tr>
            </table>
          </td>
        </tr>`;
      } else if (b.tipo === "boton") {
        contenidoBloques += `
        <tr>
          <td style="padding:16px 24px; text-align:center;">
            <a href="${urlBoton}" style="background:${colorBoton}; color:#ffffff; padding:10px 28px; font-family:Arial,sans-serif; font-size:14px; font-weight:bold; text-decoration:none; border-radius:4px; display:inline-block;">
              ${textoBoton}
            </a>
          </td>
        </tr>`;
      }
    });
    return contenidoBloques;
  }

  function generarHoja(tit, imgCab, sufijo, conPie) {
    const cabecera = imgCab
      ? `<img src="${imgCab}" alt="cabecera" style="max-width:300px; width:100%; height:auto; display:block; margin:0 auto;"/>`
      : `<img src="${logoCabezera}" alt="logo" style="width:100%; height:auto; max-width:300px; margin-top:0px; margin-bottom:0px">`;

    return `
      <table width="600" cellspacing="0" cellpadding="0" border="0" bgcolor="#FFFFFF" style="border-collapse:collapse;">
        <tr>
          <td style="padding:22px 24px; border-top:6px solid #005FB8; border-bottom:1px solid #E5E7EB; text-align:center;">
            ${cabecera}
          </td>
        </tr>
        <tr>
          <td style="padding:18px 24px 10px 24px; text-align:center;">
            <h1 style="margin:0; font-family:Arial,sans-serif; font-size:20px; color:#005FB8;">${tit || "Título del correo"}</h1>
          </td>
        </tr>
        ${renderBloquesHTML(sufijo)}
        ${conPie ? piePagina : ""}
      </table>`;
  }

  function generarHTML() {
    const hojaEs = generarHoja(titulo, imagenCabecera, "", !hojaVaActiva);
    const hojaVa = hojaVaActiva
      ? generarHoja(tituloVa, imagenCabeceraVa, "Va", true)
      : "";

    return `<html>
    <head></head>
    <body>
      <table width="100%" cellspacing="0" cellpadding="0" border="0" bgcolor="#F2F4F7" style="margin:0;padding:0;">
        <tr>
        <td align="center" style="padding:20px 0;">${hojaEs}</td>
        </tr>
        ${hojaVaActiva ? `
          <tr>
          <td align="center" style="padding:20px 0;">${hojaVa}</td>
          </tr>` : ""}
      </table>
    </body>
    </html>`;
  }

   function renderPanelBloques(esVa) {
    const sf = esVa ? "Va" : "";
    const sfCol2 = esVa ? "contenidoCol2Va" : "contenidoCol2";

    return bloques.map((b) => (
      <div key={b.id} style={{ border: "1px solid #ddd", borderRadius: 6, padding: 12, marginBottom: 12, background: "#fafafa" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
          <strong style={{ color: "#005FB8" }}>
            {b.tipo === "texto" && "Texto"}
            {b.tipo === "imagen" && "Imagen"}
            {b.tipo === "doscolumnas" && "Dos columnas"}
            {b.tipo === "caja" && "Texto en caja"}
            {b.tipo === "boton" && "Botón"}
          </strong>
          <button onClick={() => eliminarBloque(b.id)} style={{ background: "none", border: "none", color: "red", cursor: "pointer", fontSize: 16 }}>✕</button>
        </div>

        {b.tipo === "texto" && quillCargado && (
          <EditorQuill
            placeholder={esVa ? "Escriu el text ací..." : "Escribe el texto aquí..."}
            onReady={quill => guardarEditor(b.id, "contenido" + sf, quill)}
          />
        )}

        {b.tipo === "imagen" && (
          <div>
            <input type="file" accept="image/*"
              onChange={e => imagenBloqueABase64(b.id, e.target.files[0], "imagen" + sf)}
              style={{ marginBottom: 8 }}
            />
            {b["imagen" + sf] && (
              <img src={b["imagen" + sf]} alt="preview" style={{ maxWidth: "100%", maxHeight: 100, display: "block", borderRadius: 4 }} />
            )}
          </div>
        )}

        {b.tipo === "doscolumnas" && quillCargado && (
          <div style={{ display: "flex", gap: 8 }}>
            <div style={{ flex: 1, minWidth: 0, overflow: "hidden" }}>
              <label style={{ fontSize: 12, fontWeight: "bold", display: "block", marginBottom: 4 }}>Columna 1</label>
              <EditorQuill
                placeholder={esVa ? "Text de la primera columna..." : "Texto de la primera columna..."}
                onReady={quill => guardarEditor(b.id, "contenido" + sf, quill)}
              />
            </div>
            <div style={{ flex: 1, minWidth: 0, overflow: "hidden" }}>
              <label style={{ fontSize: 12, fontWeight: "bold", display: "block", marginBottom: 4 }}>Columna 2</label>
              <EditorQuill
                placeholder={esVa ? "Text de la segona columna..." : "Texto de la segunda columna..."}
                onReady={quill => guardarEditor(b.id, sfCol2, quill)}
              />
            </div>
          </div>
        )}

        {b.tipo === "caja" && quillCargado && (
          <EditorQuill
            placeholder={esVa ? "Text destacat a la caixa..." : "Texto destacado en la caja..."}
            onReady={quill => guardarEditor(b.id, "contenido" + sf, quill)}
          />
        )}

        {b.tipo === "boton" && (
          <div style={{ display: "flex", gap: 8 }}>
            <div style={{ flex: 1 }}>
              <label style={{ fontSize: 12, display: "block", marginBottom: 4 }}>Texto del botón</label>
              <input type="text" value={b["textoBoton" + sf]}
                onChange={e => actualizarBloque(b.id, "textoBoton" + sf, e.target.value)}
                style={{ width: "100%", padding: 6, border: "1px solid #ccc", borderRadius: 4, boxSizing: "border-box" }}
              />
            </div>
            <div style={{ flex: 1 }}>
              <label style={{ fontSize: 12, display: "block", marginBottom: 4 }}>URL del enlace</label>
              <input type="text" value={b["urlBoton" + sf]}
                onChange={e => actualizarBloque(b.id, "urlBoton" + sf, e.target.value)}
                placeholder="https://..."
                style={{ width: "100%", padding: 6, border: "1px solid #ccc", borderRadius: 4, boxSizing: "border-box" }}
              />
            </div>
            <div style={{ flex: 1 }}>
              <label style={{ fontSize: 12, display: "block", marginBottom: 4 }}>Color</label>
              <select value={b["colorBoton" + sf]}
                onChange={e => actualizarBloque(b.id, "colorBoton" + sf, e.target.value)}
                style={{ width: "100%", padding: 6, border: "1px solid #ccc", borderRadius: 4, boxSizing: "border-box", backgroundColor: "white" }}>
                <option value="#53565A">Gris</option>
                <option value="#005FB8">Azul</option>
              </select>
            </div>
          </div>
        )}

        {["texto", "doscolumnas", "caja"].includes(b.tipo) && !quillCargado && (
          <p style={{ color: "#999", fontSize: 13 }}>Cargando editor...</p>
        )}
      </div>
    ));
  }

  return (
    <div style={{ display: "flex", height: "100vh", width: "100vw", overflow: "hidden", fontFamily: "Arial, sans-serif" }}>

      <div style={{ width: "33.33%", height: "100%", overflowY: "auto", borderRight: "2px solid #ddd", padding: 20, boxSizing: "border-box" }}>

        <h2 style={{ color: "#005FB8", marginTop: 0 }}>Crear correo</h2>

        <div style={{ marginBottom: 15 }}>
          <button
            onClick={() => {
              const nueva = !hojaVaActiva;
              setHojaVaActiva(nueva);
              setPestanaActiva(nueva ? "va" : "es");
            }}
            style={{
              width: "160px",
              padding: "9px 16px",
              border: `2px solid ${hojaVaActiva ? "#005FB8" : "#ccc"}`,
              borderRadius: 6, 
              cursor: "pointer",
              fontWeight: "bold",
              fontSize: 14,
              background: hojaVaActiva ? "#EEF5FD" : "#f9f9f9",
              color: hojaVaActiva ? "#005FB8" : "#888",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              gap: 10,
              transition: "all 0.15s",
            }}
          >
            <span style={{
              width: 20, height: 20, borderRadius: "50%",
              border: `2px solid ${hojaVaActiva ? "#005FB8" : "#bbb"}`,
              background: hojaVaActiva ? "#005FB8" : "transparent",
              display: "inline-flex", alignItems: "center", justifyContent: "center",
              color: "#fff", fontSize: 14, flexShrink: 0,
            }}>
              {hojaVaActiva ? "✓" : ""}
            </span>
            Añadir copia
          </button>
        </div>

        {hojaVaActiva && (
          <div style={{ display: "flex", marginBottom: 20, borderBottom: "2px solid #005FB8" }}>
            {["es", "va"].map(lang => (
              <button key={lang} onClick={() => setPestanaActiva(lang)}
                style={{
                  flex: 1, padding: "8px 0", border: "none", cursor: "pointer",
                  fontWeight: "bold", fontSize: 14,
                  background: pestanaActiva === lang ? "#005FB8" : "#e8f0fb",
                  color: pestanaActiva === lang ? "#fff" : "#005FB8",
                  borderRadius: "4px 4px 0 0",
                  transition: "background 0.15s",
                }}
              >
                {lang === "es" ? "Idioma 1" : "Idioma 2"}
              </button>
            ))}
          </div>
        )}

        <div style={{ display: (!hojaVaActiva || pestanaActiva === "es") ? "block" : "none" }}>
          <div style={{ marginBottom: 25 }}>
            <label style={{ display: "block", fontWeight: "bold", marginBottom: 5 }}>
              Imagen de cabecera <span style={{ fontWeight: "normal", color: "#999", fontSize: 12 }}>(opcional)</span>
            </label>
            <input type="file" accept="image/*" onChange={e => imagenCabeceraABase64(e.target.files[0], false)} />
            {imagenCabecera && (
              <div>
                <img src={imagenCabecera} alt="cabecera" style={{ maxWidth: "100%", maxHeight: 80, borderRadius: 4, display: "block", marginBottom: 4 }} />
                <button onClick={() => setImagenCabecera("")} style={{ background: "none", border: "none", color: "red", cursor: "pointer", fontSize: 12, padding: 0 }}>
                  ✕ Quitar imagen
                </button>
              </div>
            )}
          </div>

          <div style={{ marginBottom: 20 }}>
            <label style={{ display: "block", fontWeight: "bold", marginBottom: 5 }}>Título del correo</label>
            <input type="text" value={titulo} onChange={e => setTitulo(e.target.value)}
              placeholder="Escribe el título aquí..."
              style={{ width: "100%", padding: 8, fontSize: 14, border: "1px solid #ccc", borderRadius: 4, boxSizing: "border-box" }}
            />
          </div>

          <div style={{ marginBottom: 20 }}>
            <label style={{ display: "block", fontWeight: "bold", marginBottom: 8 }}>Añadir contenido:</label>
            <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
              {["texto","imagen","doscolumnas","caja","boton"].map(tipo => (
                <button key={tipo} onClick={() => agregarBloque(tipo)} style={estiloBotonAnadir} title={
                  tipo === "texto" ? "Texto" :
                  tipo === "imagen" ? "Imagen" :
                  tipo === "doscolumnas" ? "Dos columnas" :
                  tipo === "caja" ? "Texto en caja" : "Botón"
                }>
                  <i className={
                    tipo === "texto" ? "bi bi-text-left" :
                    tipo === "imagen" ? "bi bi-image" :
                    tipo === "doscolumnas" ? "bi bi-layout-split" :
                    tipo === "caja" ? "bi bi-card-text" :
                    "bi bi-link-45deg"
                  } style={{ fontSize: 16 }} />
                </button>
              ))}
            </div>
          </div>

          {bloques.length === 0 && (
            <p style={{ color: "#999", textAlign: "center", marginTop: 40 }}>
              Pulsa un botón de arriba para añadir contenido al correo
            </p>
          )}

          {renderPanelBloques(false)}
        </div>

        <div style={{ display: (hojaVaActiva && pestanaActiva === "va") ? "block" : "none" }}>
          <div style={{ marginBottom: 25 }}>
            <label style={{ display: "block", fontWeight: "bold", marginBottom: 5 }}>
              Imatge de capçalera <span style={{ fontWeight: "normal", color: "#999", fontSize: 12 }}>(opcional)</span>
            </label>
            <input type="file" accept="image/*" onChange={e => imagenCabeceraABase64(e.target.files[0], true)} />
            {imagenCabeceraVa && (
              <div>
                <img src={imagenCabeceraVa} alt="cabecera" style={{ maxWidth: "100%", maxHeight: 80, borderRadius: 4, display: "block", marginBottom: 4 }} />
                <button onClick={() => setImagenCabeceraVa("")} style={{ background: "none", border: "none", color: "red", cursor: "pointer", fontSize: 12, padding: 0 }}>
                  ✕ Llevar imatge
                </button>
              </div>
            )}
          </div>

          <div style={{ marginBottom: 20 }}>
            <label style={{ display: "block", fontWeight: "bold", marginBottom: 5 }}>Títol del correu</label>
            <input type="text" value={tituloVa} onChange={e => setTituloVa(e.target.value)}
              placeholder="Escriu el títol ací..."
              style={{ width: "100%", padding: 8, fontSize: 14, border: "1px solid #ccc", borderRadius: 4, boxSizing: "border-box" }}
            />
          </div>

          <div style={{ marginBottom: 20 }}>
            <label style={{ display: "block", fontWeight: "bold", marginBottom: 8 }}>Afegir contingut:</label>
            <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
              {["texto","imagen","doscolumnas","caja","boton"].map(tipo => (
                <button key={tipo} onClick={() => agregarBloque(tipo)} style={estiloBotonAnadir}>
                  {tipo === "texto" && "Texto"}
                  {tipo === "imagen" && "Imagen"}
                  {tipo === "doscolumnas" && "Dos columnas"}
                  {tipo === "caja" && "Texto en caja"}
                  {tipo === "boton" && "Botón"}
                </button>
              ))}
            </div>
          </div>

          {bloques.length === 0 && (
            <p style={{ color: "#999", textAlign: "center", marginTop: 40 }}>
              Polsa un botó de dalt per a afegir contingut al correu
            </p>
          )}

          {renderPanelBloques(true)}
        </div>

        <button onClick={copiarHTML}
          style={{
            width: "100%", padding: 10, marginTop: 8,
            background: copiado ? "#16a34a" : "#1e293b",
            color: "#fff", border: "none", borderRadius: 4,
            cursor: "pointer", fontSize: 14, fontWeight: "bold"
          }}>
          {copiado ? "HTML copiado al portapapeles ✅" : "Copiar HTML del correo 📋"}
        </button>

      </div>

      <div style={{ width: "66.66%", height: "100%", display: "flex", flexDirection: "column" }}>
        <div style={{ background: "#333", color: "#ccc", padding: "8px 16px", fontSize: 12, flexShrink: 0 }}>
          Vista previa del correo{hojaVaActiva ? " (Español + Valencià)" : " (Español)"}
        </div>
        <iframe srcDoc={html} style={{ flex: 1, width: "100%", border: "none" }} title="preview" />
      </div>

    </div>
  );
}
const estiloBotonAnadir = {
  padding: "7px 14px",
  background: "#005FB8",
  color: "#fff",
  border: "none",
  borderRadius: 4,
  cursor: "pointer",
  fontSize: 13,
};